SKILL = {'name': 'basic_arithmetic_module', 'keywords': ['arithmetic', 'validation', 'type checking', 'division by zero', 'function signature', 'assert', 'isinstance'], 'prompt_fragment': 'Implement core arithmetic operations (sum, subtract, multiply, divide) with type validation. Ensure division handles zero divisor by returning None. Validate input types using isinstance. Include callable and result assertions for verification. Keep functions simple and focused on single responsibility.', 'example_code': 'def suma(a, b):\n    return a + b\n\ndef resta(a, b):\n    return a - b\n\ndef multiplicacion(a, b):\n    return a * b\n\ndef division(a, b):\n    if b == 0:\n        return None\n    return a / b\n\ndef validar_tipo(valor, tipo):\n    return isinstance(valor, tipo)\n\nif __name__ == \'__main__\':\n    assert callable(suma)\n    assert suma(2, 3) == 5\n    assert division(10, 2) == 5.0\n    assert division(1, 0) is None\n    assert validar_tipo(5, int) is True\n    assert validar_tipo("hola", str) is True\n    print("CRITERIO OK")'}
